<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Falling Sand</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #0d1117;
    color: #c9d1d9;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Helvetica, Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    overflow: hidden;
    user-select: none;
  }
  h1 {
    font-size: 1.4rem;
    margin-bottom: 12px;
    letter-spacing: 0.5px;
    color: #8b949e;
    font-weight: 600;
  }
  #sand {
    border: 2px solid #30363d;
    border-radius: 6px;
    image-rendering: pixelated;
    image-rendering: crisp-edges;
    cursor: crosshair;
    display: block;
    min-width: 480px;
    min-height: 360px;
    background: #161b22;
  }
  .controls {
    margin-top: 14px;
    display: flex;
    gap: 8px;
    align-items: center;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    background: #21262d;
    color: #c9d1d9;
    border: 1px solid #30363d;
    padding: 8px 16px;
    font-size: 0.85rem;
    font-weight: 500;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
    letter-spacing: 0.3px;
  }
  button:hover { background: #30363d; border-color: #484f58; }
  button.active {
    background: #388bfd22;
    border-color: #58a6ff;
    color: #58a6ff;
    box-shadow: 0 0 8px #58a6ff33;
  }
  #clear {
    margin-left: 12px;
    background: #da363322;
    border-color: #f8514966;
    color: #f85149;
  }
  #clear:hover { background: #f8514944; border-color: #f85149; }
  .info {
    margin-top: 10px;
    font-size: 0.72rem;
    color: #484f58;
  }
</style>
</head>
<body>

<h1>Falling Sand Sandbox</h1>
<canvas id="sand" width="640" height="480"></canvas>
<div class="controls">
  <button id="mat-sand" class="active">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear All</button>
</div>
<div class="info">Click &amp; drag on the canvas to paint · Bottom-up simulation, no teleporting</div>

<script>
(function() {
  "use strict";

  // ── Grid dimensions ──────────────────────────────────────────────
  var W = 160;
  var H = 120;
  var CELL_W = 4;   // internal pixels per cell → canvas is 640×480
  var CELL_H = 4;

  // ── Material constants ───────────────────────────────────────────
  var EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  var MAT_NAMES = ["empty","sand","water","wall","acid"];

  // ── Grid storage (flat array) ────────────────────────────────────
  var grid = new Int8Array(W * H);

  function idx(x, y) { return y * W + x; }
  function inBounds(x, y) { return x >= 0 && x < W && y >= 0 && y < H; }

  // ── Simulation tick (single step) ────────────────────────────────
  function tick() {
    // Process bottom-to-top so each particle moves at most one cell
    for (var row = H - 1; row >= 0; row--) {
      for (var col = 0; col < W; col++) {
        var i = idx(col, row);
        var mat = grid[i];
        if (mat === EMPTY || mat === WALL) continue;

        if (mat === SAND) {
          // Try fall straight down
          if (row + 1 < H) {
            var below = idx(col, row + 1);
            var bMat = grid[below];
            if (bMat === EMPTY) {
              grid[below] = SAND; grid[i] = EMPTY;
            } else if (bMat === WATER || bMat === ACID) {
              // Swap: sand sinks through liquid
              grid[below] = SAND; grid[i] = bMat;
            } else {
              // Try diagonal left-down or right-down
              var dir = Math.random() < 0.5 ? -1 : 1;
              var moved = false;
              for (var d = 0; d < 2; d++) {
                var dx = (d === 0) ? dir : -dir;
                if (col + dx >= 0 && col + dx < W && row + 1 < H) {
                  var diag = idx(col + dx, row + 1);
                  if (grid[diag] === EMPTY || grid[diag] === WATER || grid[diag] === ACID) {
                    var swapMat = grid[diag];
                    grid[diag] = SAND;
                    if (swapMat === WATER || swapMat === ACID) {
                      // Also swap liquid up slightly
                      grid[i] = swapMat;
                    } else {
                      grid[i] = EMPTY;
                    }
                    moved = true;
                    break;
                  }
                }
              }
            }
          }
        }

        else if (mat === WATER || mat === ACID) {
          // Try fall straight down
          var fell = false;
          if (row + 1 < H) {
            var below2 = idx(col, row + 1);
            if (grid[below2] === EMPTY) {
              grid[below2] = mat; grid[i] = EMPTY;
              fell = true;
            } else if (grid[below2] === SAND && mat === ACID) {
              // Acid dissolves sand below
              if (Math.random() < 0.5) {
                grid[below2] = EMPTY;
                // acid stays or also disappears
                if (Math.random() < 0.3) {
                  grid[i] = EMPTY;
                }
              }
              fell = true;
            }
          }

          if (!fell && mat === ACID) {
            // Acid dissolves adjacent sand/wall (beside)
            var dissolved = false;
            var neighbors = [[-1,0],[1,0]];
            var nDir = Math.random() < 0.5 ? 0 : 1;
            for (var nd = 0; nd < 2; nd++) {
              var ni = (nd === 0) ? nDir : 1 - nDir;
              var nx = col + neighbors[ni][0];
              var ny = row + neighbors[ni][1];
              if (inBounds(nx, ny)) {
                var nMat = grid[idx(nx, ny)];
                if (nMat === SAND || nMat === WALL) {
                  grid[idx(nx, ny)] = EMPTY;
                  dissolved = true;
                  if (Math.random() < 0.25) {
                    grid[i] = EMPTY; // acid consumed
                  }
                  break;
                }
              }
            }
          }

          if (!fell && mat !== ACID) {
            // Water spreads horizontally
            spreadHorizontal(col, row, WATER);
          } else if (!fell && mat === ACID && !dissolved) {
            spreadHorizontal(col, row, ACID);
          }
        }
      }
    }
  }

  function spreadHorizontal(startCol, startRow, mat) {
    // Randomize direction first
    var dir = Math.random() < 0.5 ? -1 : 1;
    for (var step = 0; step < 2; step++) {
      var dx = (step === 0) ? dir : -dir;
      var nx = startCol + dx;
      if (nx >= 0 && nx < W) {
        var ni = idx(nx, startRow);
        if (grid[ni] === EMPTY) {
          grid[ni] = mat;
          // Don't set current to empty — water stays and fills space
          return;
        }
      }
    }
  }

  // ── Rendering ────────────────────────────────────────────────────
  var canvas = document.getElementById("sand");
  var ctx = canvas.getContext("2d");
  var imgData = ctx.createImageData(W, H);

  function render() {
    var data = imgData.data;
    for (var y = 0; y < H; y++) {
      for (var x = 0; x < W; x++) {
        var i = idx(x, y);
        var mat = grid[i];
        var p = (y * W + x) * 4;

        if (mat === EMPTY) {
          data[p]     = 22;
          data[p + 1] = 27;
          data[p + 2] = 34;
          data[p + 3] = 255;
        } else if (mat === SAND) {
          var v = ((x * 7 + y * 13) % 6) - 3;
          data[p]     = Math.min(255, Math.max(0, 220 + v));
          data[p + 1] = Math.min(255, Math.max(0, 190 + v));
          data[p + 2] = Math.min(255, Math.max(0, 60 + v));
          data[p + 3] = 255;
        } else if (mat === WATER) {
          var wv = ((x * 11 + y * 7) % 8) - 4;
          data[p]     = Math.min(255, Math.max(0, 40 + wv));
          data[p + 1] = Math.min(255, Math.max(0, 160 + wv));
          data[p + 2] = Math.min(255, Math.max(0, 240 + wv));
          data[p + 3] = 255;
        } else if (mat === WALL) {
          var wv2 = ((x * 3 + y * 17) % 10) - 5;
          data[p]     = Math.min(255, Math.max(0, 90 + wv2));
          data[p + 1] = Math.min(255, Math.max(0, 90 + wv2));
          data[p + 2] = Math.min(255, Math.max(0, 95 + wv2));
          data[p + 3] = 255;
        } else if (mat === ACID) {
          var av = ((x * 13 + y * 5) % 6) - 3;
          data[p]     = Math.min(255, Math.max(0, 80 + av));
          data[p + 1] = Math.min(255, Math.max(0, 240 + av));
          data[p + 2] = Math.min(255, Math.max(0, 30 + av));
          data[p + 3] = 255;
        }
      }
    }
    ctx.putImageData(imgData, 0, 0);
  }

  // ── Programmatic API ─────────────────────────────────────────────
  window.sim = {
    w: W,
    h: H,

    tick: function(n) {
      for (var i = 0; i < n; i++) tick();
    },

    get: function(x, y) {
      if (!inBounds(x, y)) return "empty";
      return MAT_NAMES[grid[idx(x, y)]] || "empty";
    },

    set: function(x, y, material) {
      if (!inBounds(x, y)) return;
      var m = MATERIAL_MAP[material];
      if (m !== undefined) grid[idx(x, y)] = m;
    },

    clear: function() {
      grid.fill(EMPTY);
    }
  };

  var MATERIAL_MAP = {"empty": EMPTY, "sand": SAND, "water": WATER, "wall": WALL, "acid": ACID};

  // ── UI: Material selection ───────────────────────────────────────
  var currentMat = SAND;
  var buttons = {
    sand: document.getElementById("mat-sand"),
    water: document.getElementById("mat-water"),
    wall: document.getElementById("mat-wall"),
    acid: document.getElementById("mat-acid"),
    empty: document.getElementById("mat-empty")
  };

  function setActive(name) {
    for (var key in buttons) buttons[key].classList.remove("active");
    if (buttons[name]) buttons[name].classList.add("active");
  }

  buttons.sand.addEventListener("click", function() { currentMat = SAND; setActive("sand"); });
  buttons.water.addEventListener("click", function() { currentMat = WATER; setActive("water"); });
  buttons.wall.addEventListener("click", function() { currentMat = WALL; setActive("wall"); });
  buttons.acid.addEventListener("click", function() { currentMat = ACID; setActive("acid"); });
  buttons.empty.addEventListener("click", function() { currentMat = EMPTY; setActive("empty"); });

  document.getElementById("clear").addEventListener("click", function() {
    grid.fill(EMPTY);
  });

  // ── Painting on canvas ───────────────────────────────────────────
  var painting = false;
  var brushSize = 3; // radius in cells

  function getCellFromEvent(e) {
    var rect = canvas.getBoundingClientRect();
    var scaleX = W / rect.width;
    var scaleY = H / rect.height;
    var cx = Math.floor((e.clientX - rect.left) * scaleX);
    var cy = Math.floor((e.clientY - rect.top) * scaleY);
    return { x: cx, y: cy };
  }

  function paintCell(px, py) {
    if (!inBounds(px, py)) return;
    for (var dy = -Math.floor(brushSize / 2); dy <= Math.floor(brushSize / 2); dy++) {
      for (var dx = -Math.floor(brushSize / 2); dx <= Math.floor(brushSize / 2); dx++) {
        var nx = px + dx, ny = py + dy;
        if (inBounds(nx, ny)) {
          // Circle brush
          if (dx * dx + dy * dy <= (brushSize / 2) * (brushSize / 2)) {
            grid[idx(nx, ny)] = currentMat;
          }
        }
      }
    }
  }

  canvas.addEventListener("mousedown", function(e) {
    painting = true;
    var c = getCellFromEvent(e);
    paintCell(c.x, c.y);
  });
  canvas.addEventListener("mousemove", function(e) {
    if (!painting) return;
    var c = getCellFromEvent(e);
    paintCell(c.x, c.y);
  });
  window.addEventListener("mouseup", function() { painting = false; });

  // Touch support
  canvas.addEventListener("touchstart", function(e) {
    e.preventDefault();
    painting = true;
    var t = e.touches[0];
    var c = getCellFromEvent(t);
    paintCell(c.x, c.y);
  }, { passive: false });
  canvas.addEventListener("touchmove", function(e) {
    e.preventDefault();
    if (!painting) return;
    var t = e.touches[0];
    var c = getCellFromEvent(t);
    paintCell(c.x, c.y);
  }, { passive: false });
  window.addEventListener("touchend", function() { painting = false; });

  // ── Animation loop ───────────────────────────────────────────────
  var lastTime = 0;
  var simSpeed = 2; // ticks per frame at 60fps
  var tickAccum = 0;

  function animate(time) {
    requestAnimationFrame(animate);
    if (!lastTime) { lastTime = time; return; }
    var dt = time - lastTime;
    lastTime = time;

    // Run simulation at ~60 ticks/sec
    tickAccum += dt;
    var step = 1000 / 60;
    while (tickAccum >= step) {
      tick();
      tickAccum -= step;
    }
    render();
  }

  requestAnimationFrame(animate);

})();
</script>
</body>
</html>
